import React, { useEffect, useState } from 'react';
import { LogOut, Users, Mail } from 'lucide-react';
import { db } from '../firebase';
import { collection, onSnapshot } from 'firebase/firestore';
import { useLang } from '../context/LangContext';
import { useAuth } from '../context/AuthContext';
import UserAvatar from '../components/UserAvatar';

export default function UsersPage() {
  const { t, lang, toggleLang } = useLang();
  const { user, userProfile, logout } = useAuth();
  const [users, setUsers] = useState([]);

  useEffect(() => {
    const unsub = onSnapshot(collection(db, 'users'), snap => {
      setUsers(snap.docs.map(d => ({ id: d.id, ...d.data() })));
    });
    return unsub;
  }, []);

  const getInitials = (name) => (name || 'U').split(' ').map(n => n[0]).join('').slice(0,2).toUpperCase();
  const avatarColors = ['#1a5276','#117a65','#784212','#6c3483','#922b21'];
  const avatarColor = (email) => avatarColors[(email || '').charCodeAt(0) % avatarColors.length];

  const displayName = userProfile?.name || user?.displayName || 'User';
  const email = user?.email || userProfile?.email || '';

  return (
    <div style={styles.page}>
      <div style={styles.topBar}>
        <h2 style={styles.title}>{t.users}</h2>
        <button style={styles.langBtn} onClick={toggleLang}>
          {lang === 'en' ? 'தமிழ்' : 'English'}
        </button>
      </div>

      {/* My profile card */}
      <div style={styles.myCard}>
        <div style={styles.avatarWrap}>
          <UserAvatar size={64} />
        </div>
        <div style={{ flex: 1 }}>
          <p style={styles.myName}>{displayName}</p>
          <div style={styles.emailRow}>
            <Mail size={12} color="rgba(255,255,255,0.6)" />
            <p style={styles.myEmail}>{email}</p>
          </div>
          <span style={styles.roleBadge}>
            {userProfile?.role === 'admin' ? t.admin : t.member}
          </span>
        </div>
      </div>

      {/* All users */}
      <div style={styles.section}>
        <div style={styles.sectionHeader}>
          <Users size={16} color="#1a3a5c" />
          <span style={styles.sectionTitle}>{t.users} ({users.length})</span>
        </div>

        {users.map(u => (
          <div key={u.id} style={styles.userRow}>
            {/* Avatar — Google photo or initials */}
            {u.photoURL ? (
              <img src={u.photoURL} alt={u.name} referrerPolicy="no-referrer"
                style={{ width: 42, height: 42, borderRadius: '50%', objectFit: 'cover', flexShrink: 0 }} />
            ) : (
              <div style={{ ...styles.avatar, background: avatarColor(u.email) }}>
                <span style={styles.avatarText}>{getInitials(u.name)}</span>
              </div>
            )}
            <div style={{ flex: 1 }}>
              <p style={styles.userName}>{u.name}</p>
              <p style={styles.userEmail}>{u.email}</p>
            </div>
            <span style={{ ...styles.badge, ...(u.role === 'admin' ? styles.adminBadge : styles.memberBadge) }}>
              {u.role === 'admin' ? t.admin : t.member}
            </span>
          </div>
        ))}
      </div>

      {/* Logout */}
      <div style={styles.logoutSection}>
        <button style={styles.logoutBtn} onClick={logout}>
          <LogOut size={18} />
          {t.logout}
        </button>
      </div>
    </div>
  );
}

const styles = {
  page: { paddingBottom: 90 },
  topBar: { background: '#1a3a5c', padding: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  title: { color: '#fff', fontSize: 18, fontWeight: 700, margin: 0 },
  langBtn: { padding: '6px 14px', background: 'rgba(255,255,255,0.15)', color: '#fff', border: '1px solid rgba(255,255,255,0.3)', borderRadius: 8, fontSize: 13, cursor: 'pointer' },
  myCard: { margin: '16px 12px', background: 'linear-gradient(135deg,#1a3a5c,#1a5276)', borderRadius: 16, padding: '20px 16px', display: 'flex', gap: 16, alignItems: 'center' },
  avatarWrap: { flexShrink: 0 },
  myName: { color: '#fff', fontSize: 17, fontWeight: 700, margin: '0 0 4px' },
  emailRow: { display: 'flex', alignItems: 'center', gap: 5, marginBottom: 8 },
  myEmail: { color: 'rgba(255,255,255,0.65)', fontSize: 12, margin: 0 },
  roleBadge: { fontSize: 11, padding: '3px 10px', borderRadius: 12, background: 'rgba(255,255,255,0.2)', color: '#fff', fontWeight: 600 },
  section: { margin: '0 12px' },
  sectionHeader: { display: 'flex', alignItems: 'center', gap: 8, marginBottom: 10 },
  sectionTitle: { fontSize: 15, fontWeight: 700, color: '#1a3a5c' },
  userRow: { background: '#fff', borderRadius: 12, padding: '12px', marginBottom: 8, display: 'flex', alignItems: 'center', gap: 12, boxShadow: '0 1px 4px rgba(0,0,0,0.05)' },
  avatar: { width: 42, height: 42, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 },
  avatarText: { color: '#fff', fontSize: 14, fontWeight: 700 },
  userName: { fontSize: 14, fontWeight: 600, color: '#1a3a5c', margin: '0 0 2px' },
  userEmail: { fontSize: 11, color: '#999', margin: 0 },
  badge: { fontSize: 10, padding: '3px 8px', borderRadius: 6, fontWeight: 600, flexShrink: 0 },
  adminBadge: { background: '#eaf1f8', color: '#1a5276' },
  memberBadge: { background: '#f0f0f0', color: '#888' },
  logoutSection: { margin: '20px 12px' },
  logoutBtn: { width: '100%', padding: '13px', background: '#fff', color: '#c0392b', border: '1.5px solid #e74c3c', borderRadius: 12, fontSize: 15, fontWeight: 600, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8 }
};
