import React, { useEffect, useState } from 'react';
import { TrendingUp, Package, CreditCard, IndianRupee, AlertTriangle, Edit2 } from 'lucide-react';
import { listenTo, saveBudget } from '../utils/firestore';
import { db } from '../firebase';
import { doc, onSnapshot } from 'firebase/firestore';
import { useLang } from '../context/LangContext';
import { useAuth } from '../context/AuthContext';
import UserAvatar from '../components/UserAvatar';

export default function Dashboard() {
  const { t } = useLang();
  const { userProfile, user } = useAuth();
  const [materials, setMaterials] = useState([]);
  const [payments, setPayments] = useState([]);
  const [logs, setLogs] = useState([]);
  const [budget, setBudget] = useState(0);
  const [editBudget, setEditBudget] = useState(false);
  const [budgetInput, setBudgetInput] = useState('');

  useEffect(() => {
    const u1 = listenTo('materials', setMaterials);
    const u2 = listenTo('payments', setPayments);
    const u3 = listenTo('logs', setLogs);
    const u4 = onSnapshot(doc(db, 'settings', 'budget'), snap => {
      if (snap.exists()) setBudget(snap.data().amount || 0);
    });
    return () => { u1(); u2(); u3(); u4(); };
  }, []);

  const totalMaterials = materials.reduce((s, m) => s + (Number(m.totalCost) || 0), 0);
  const totalPayments = payments.reduce((s, p) => s + (Number(p.amount) || 0), 0);
  const totalSpent = totalMaterials + totalPayments;
  const remaining = budget - totalSpent;

  const fmtINR = (v) => '₹' + Number(v).toLocaleString('en-IN');
  const fmtTime = (ts) => {
    if (!ts) return '';
    const d = ts.toDate ? ts.toDate() : new Date(ts);
    return d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short' }) + ' ' + d.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });
  };

  const saveBudgetValue = async () => {
    await saveBudget(Number(budgetInput));
    setBudget(Number(budgetInput));
    setEditBudget(false);
  };

  const displayName = userProfile?.name || user?.displayName || 'User';
  const firstName = displayName.split(' ')[0];

  const cards = [
    { label: t.totalSpent, value: fmtINR(totalSpent), color: '#1a5276', icon: IndianRupee },
    { label: t.totalMaterials, value: fmtINR(totalMaterials), color: '#117a65', icon: Package },
    { label: t.totalPayments, value: fmtINR(totalPayments), color: '#784212', icon: CreditCard },
    { label: t.balance, value: fmtINR(remaining), color: remaining < 0 ? '#922b21' : '#1d6a3a', icon: TrendingUp }
  ];

  return (
    <div style={styles.page}>
      {/* Header */}
      <div style={styles.header}>
        <div>
          <h1 style={styles.appTitle}>SVS</h1>
          <p style={styles.appSub}>{t.welcome}, {firstName} 👋</p>
        </div>
        <UserAvatar size={42} />
      </div>

      {/* Budget bar */}
      <div style={styles.budgetCard}>
        <div style={styles.budgetRow}>
          <span style={styles.budgetLabel}>{t.totalBudget}</span>
          <button style={styles.editBudgetBtn} onClick={() => { setEditBudget(true); setBudgetInput(budget); }}>
            <Edit2 size={14} />
          </button>
        </div>
        {editBudget ? (
          <div style={styles.budgetEditRow}>
            <input style={styles.budgetInput} type="number" value={budgetInput} onChange={e => setBudgetInput(e.target.value)} autoFocus />
            <button style={styles.saveBudgetBtn} onClick={saveBudgetValue}>{t.save}</button>
            <button style={styles.cancelBudgetBtn} onClick={() => setEditBudget(false)}>{t.cancel}</button>
          </div>
        ) : (
          <p style={styles.budgetValue}>{fmtINR(budget)}</p>
        )}
        {budget > 0 && (
          <>
            <div style={styles.progressBg}>
              <div style={{ ...styles.progressFill, width: `${Math.min((totalSpent / budget) * 100, 100)}%`, background: totalSpent > budget ? '#e74c3c' : '#27ae60' }} />
            </div>
            <div style={styles.progressLabels}>
              <span style={{ fontSize: 11, color: '#888' }}>{Math.round((totalSpent / budget) * 100)}% {t.totalSpent.toLowerCase()}</span>
              {remaining < 0 && <span style={{ fontSize: 11, color: '#e74c3c', display: 'flex', alignItems: 'center', gap: 3 }}><AlertTriangle size={11} />{t.budgetWarning}</span>}
            </div>
          </>
        )}
      </div>

      {/* Stat cards */}
      <div style={styles.grid}>
        {cards.map(card => {
          const Icon = card.icon;
          return (
            <div key={card.label} style={{ ...styles.card, borderLeft: `4px solid ${card.color}` }}>
              <Icon size={18} color={card.color} style={{ marginBottom: 6 }} />
              <p style={styles.cardValue}>{card.value}</p>
              <p style={styles.cardLabel}>{card.label}</p>
            </div>
          );
        })}
      </div>

      {/* Recent logs */}
      <div style={styles.section}>
        <h2 style={styles.sectionTitle}>{t.recentActivity}</h2>
        {logs.slice(0, 8).map(log => (
          <div key={log.id} style={styles.logRow}>
            <div style={styles.logDot} />
            <div style={{ flex: 1 }}>
              <p style={styles.logText}>{log.details}</p>
              <p style={styles.logMeta}>{log.userName} · {fmtTime(log.timestamp)}</p>
            </div>
          </div>
        ))}
        {logs.length === 0 && <p style={styles.empty}>{t.noData}</p>}
      </div>
    </div>
  );
}

const styles = {
  page: { padding: '0 0 90px' },
  header: { background: 'linear-gradient(135deg, #1a3a5c, #1a5276)', padding: '20px 16px 24px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' },
  appTitle: { fontSize: 24, fontWeight: 900, color: '#fff', margin: 0, letterSpacing: 3 },
  appSub: { fontSize: 13, color: 'rgba(255,255,255,0.75)', margin: '3px 0 0' },
  budgetCard: { margin: '16px 12px 0', background: '#fff', borderRadius: 12, padding: '14px 16px', boxShadow: '0 2px 8px rgba(0,0,0,0.07)' },
  budgetRow: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 4 },
  budgetLabel: { fontSize: 12, color: '#888', fontWeight: 500 },
  editBudgetBtn: { background: 'none', border: 'none', cursor: 'pointer', padding: 4, color: '#666' },
  budgetValue: { fontSize: 22, fontWeight: 700, color: '#1a3a5c', margin: '0 0 10px' },
  budgetEditRow: { display: 'flex', gap: 6, alignItems: 'center', marginBottom: 10 },
  budgetInput: { flex: 1, padding: '6px 10px', border: '1.5px solid #ddd', borderRadius: 6, fontSize: 15 },
  saveBudgetBtn: { padding: '6px 14px', background: '#1a5276', color: '#fff', border: 'none', borderRadius: 6, fontSize: 13, cursor: 'pointer' },
  cancelBudgetBtn: { padding: '6px 10px', background: '#eee', border: 'none', borderRadius: 6, fontSize: 13, cursor: 'pointer' },
  progressBg: { background: '#eee', borderRadius: 4, height: 6, overflow: 'hidden' },
  progressFill: { height: '100%', borderRadius: 4, transition: 'width 0.5s' },
  progressLabels: { display: 'flex', justifyContent: 'space-between', marginTop: 4 },
  grid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, padding: '12px 12px 0' },
  card: { background: '#fff', borderRadius: 10, padding: '14px 12px', boxShadow: '0 2px 6px rgba(0,0,0,0.05)' },
  cardValue: { fontSize: 18, fontWeight: 700, color: '#1a3a5c', margin: '0 0 3px' },
  cardLabel: { fontSize: 11, color: '#888', margin: 0 },
  section: { margin: '16px 12px 0' },
  sectionTitle: { fontSize: 15, fontWeight: 700, color: '#1a3a5c', marginBottom: 10 },
  logRow: { display: 'flex', gap: 10, paddingBottom: 12, alignItems: 'flex-start' },
  logDot: { width: 8, height: 8, borderRadius: '50%', background: '#1a5276', marginTop: 5, flexShrink: 0 },
  logText: { fontSize: 13, color: '#333', margin: '0 0 2px' },
  logMeta: { fontSize: 11, color: '#aaa', margin: 0 },
  empty: { textAlign: 'center', color: '#bbb', padding: '20px 0', fontSize: 13 }
};
