import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useLang } from '../context/LangContext';

export default function LoginPage() {
  const { loginWithGoogle } = useAuth();
  const { lang, toggleLang } = useLang();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleGoogle = async () => {
    setError('');
    setLoading(true);
    try {
      await loginWithGoogle();
    } catch (e) {
      setError(lang === 'ta' ? 'உள்நுழைவு தோல்வி. மீண்டும் முயல்க.' : 'Login failed. Please try again.');
    }
    setLoading(false);
  };

  return (
    <div style={styles.bg}>
      {/* Language toggle */}
      <button onClick={toggleLang} style={styles.langBtn}>
        {lang === 'en' ? 'தமிழ்' : 'English'}
      </button>

      <div style={styles.card}>
        {/* House logo */}
        <div style={styles.logoWrap}>
          <div style={styles.logoBox}>
            <svg width="52" height="52" viewBox="0 0 52 52" fill="none">
              <rect width="52" height="52" rx="14" fill="#1a3a5c"/>
              <path d="M26 10L42 24H37V42H29V31H23V42H15V24H10L26 10Z" fill="white"/>
              <rect x="22" y="31" width="8" height="11" fill="#1a3a5c"/>
            </svg>
          </div>
          <h1 style={styles.appName}>SVS</h1>
          <p style={styles.appSub}>
            {lang === 'ta' ? 'வீடு மேலாண்மை' : 'House Management'}
          </p>
        </div>

        {/* Divider */}
        <div style={styles.divider} />

        {/* Welcome text */}
        <p style={styles.welcomeTitle}>
          {lang === 'ta' ? 'வரவேற்கிறோம்' : 'Welcome back'}
        </p>
        <p style={styles.welcomeSub}>
          {lang === 'ta'
            ? 'தொடர உங்கள் Google கணக்கில் உள்நுழையவும்'
            : 'Sign in with your Google account to continue'}
        </p>

        {/* Google button */}
        <button style={{ ...styles.googleBtn, opacity: loading ? 0.7 : 1 }} onClick={handleGoogle} disabled={loading}>
          {loading ? (
            <div style={styles.spinner} />
          ) : (
            <svg width="20" height="20" viewBox="0 0 48 48">
              <path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.72 17.74 9.5 24 9.5z"/>
              <path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/>
              <path fill="#FBBC05" d="M10.53 28.59c-.48-1.45-.76-2.99-.76-4.59s.27-3.14.76-4.59l-7.98-6.19C.92 16.46 0 20.12 0 24c0 3.88.92 7.54 2.56 10.78l7.97-6.19z"/>
              <path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.18 1.48-4.97 2.31-8.16 2.31-6.26 0-11.57-4.22-13.47-9.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"/>
              <path fill="none" d="M0 0h48v48H0z"/>
            </svg>
          )}
          <span style={styles.googleBtnText}>
            {loading
              ? (lang === 'ta' ? 'உள்நுழைகிறது...' : 'Signing in...')
              : (lang === 'ta' ? 'Google மூலம் உள்நுழை' : 'Continue with Google')}
          </span>
        </button>

        {error && <p style={styles.error}>{error}</p>}

        <p style={styles.note}>
          {lang === 'ta'
            ? '🔒 பாதுகாப்பான Google உள்நுழைவு · SMS கட்டணம் இல்லை'
            : '🔒 Secure Google login · No SMS charges'}
        </p>
      </div>

      {/* Bottom brand */}
      <p style={styles.brand}>SVS House Management © 2025</p>
    </div>
  );
}

const styles = {
  bg: {
    minHeight: '100vh',
    background: 'linear-gradient(160deg, #0e2438 0%, #1a5276 60%, #117a65 100%)',
    display: 'flex', flexDirection: 'column',
    alignItems: 'center', justifyContent: 'center',
    padding: 20, position: 'relative'
  },
  langBtn: {
    position: 'absolute', top: 18, right: 18,
    background: 'rgba(255,255,255,0.15)', color: '#fff',
    border: '1px solid rgba(255,255,255,0.3)',
    borderRadius: 8, padding: '6px 14px', cursor: 'pointer',
    fontSize: 13, fontWeight: 500
  },
  card: {
    background: '#fff', borderRadius: 20, padding: '36px 28px 28px',
    width: '100%', maxWidth: 360,
    boxShadow: '0 24px 64px rgba(0,0,0,0.35)'
  },
  logoWrap: { textAlign: 'center', marginBottom: 20 },
  logoBox: { display: 'inline-block', marginBottom: 12 },
  appName: { fontSize: 28, fontWeight: 900, color: '#1a3a5c', margin: '0 0 4px', letterSpacing: 3 },
  appSub: { fontSize: 13, color: '#888', margin: 0 },
  divider: { height: 1, background: '#f0f0f0', margin: '0 0 20px' },
  welcomeTitle: { fontSize: 18, fontWeight: 700, color: '#1a3a5c', textAlign: 'center', margin: '0 0 6px' },
  welcomeSub: { fontSize: 12, color: '#999', textAlign: 'center', margin: '0 0 24px', lineHeight: 1.5 },
  googleBtn: {
    width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center',
    gap: 12, padding: '13px 16px',
    background: '#fff', border: '1.5px solid #ddd',
    borderRadius: 12, cursor: 'pointer', fontSize: 15, fontWeight: 600,
    color: '#333', boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
    transition: 'box-shadow 0.2s'
  },
  googleBtnText: { fontSize: 14, fontWeight: 600, color: '#333' },
  spinner: {
    width: 20, height: 20, borderRadius: '50%',
    border: '2px solid #ddd', borderTopColor: '#1a5276',
    animation: 'spin 0.7s linear infinite'
  },
  error: { color: '#c0392b', fontSize: 12, textAlign: 'center', marginTop: 10 },
  note: { fontSize: 11, color: '#bbb', textAlign: 'center', marginTop: 16 },
  brand: { color: 'rgba(255,255,255,0.3)', fontSize: 11, marginTop: 24 }
};
