import React, { useEffect, useState } from 'react';
import { Plus, Edit2, Trash2, X } from 'lucide-react';
import { listenTo, addPayment, updatePayment, deletePayment } from '../utils/firestore';
import { useLang } from '../context/LangContext';
import { useAuth } from '../context/AuthContext';

const emptyForm = { paymentTo: '', amount: '', date: new Date().toISOString().split('T')[0], note: '' };

const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];

export default function Payments() {
  const { t } = useLang();
  const { userProfile } = useAuth();
  const [items, setItems] = useState([]);
  const [modal, setModal] = useState(false);
  const [form, setForm] = useState(emptyForm);
  const [editId, setEditId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [filterMonth, setFilterMonth] = useState('all');

  useEffect(() => { return listenTo('payments', setItems); }, []);

  const open = (item = null) => {
    if (item) { setForm({ ...item }); setEditId(item.id); }
    else { setForm(emptyForm); setEditId(null); }
    setModal(true);
  };

  const handleSave = async () => {
    if (!form.paymentTo || !form.amount) return;
    setLoading(true);
    if (editId) await updatePayment(editId, form, userProfile);
    else await addPayment(form, userProfile);
    setModal(false);
    setLoading(false);
  };

  const handleDelete = async (item) => {
    if (!window.confirm(t.confirmDelete)) return;
    await deletePayment(item.id, item, userProfile);
  };

  const filtered = filterMonth === 'all' ? items
    : items.filter(i => {
      if (!i.date) return false;
      const d = new Date(i.date);
      return MONTHS[d.getMonth()] === filterMonth;
    });

  const total = filtered.reduce((s, i) => s + (Number(i.amount) || 0), 0);

  // Group by month
  const groups = {};
  filtered.forEach(i => {
    const d = new Date(i.date);
    const key = isNaN(d) ? 'Other' : MONTHS[d.getMonth()] + ' ' + d.getFullYear();
    if (!groups[key]) groups[key] = [];
    groups[key].push(i);
  });

  return (
    <div style={styles.page}>
      <div style={styles.topBar}>
        <h2 style={styles.title}>{t.payments}</h2>
        <button style={styles.addBtn} onClick={() => open()}>
          <Plus size={18} color="#fff" />
        </button>
      </div>

      {/* Month filter */}
      <div style={styles.catScroll}>
        <button style={{ ...styles.chip, ...(filterMonth === 'all' ? styles.chipActive : {}) }} onClick={() => setFilterMonth('all')}>{t.all}</button>
        {MONTHS.map(m => (
          <button key={m} style={{ ...styles.chip, ...(filterMonth === m ? styles.chipActive : {}) }} onClick={() => setFilterMonth(m)}>{m}</button>
        ))}
      </div>

      <div style={styles.totalBanner}>
        <span style={styles.tLabel}>{t.totalPayments}</span>
        <span style={styles.tValue}>₹{Number(total).toLocaleString('en-IN')}</span>
      </div>

      <div style={styles.list}>
        {Object.keys(groups).length === 0 && <p style={styles.empty}>{t.noData}</p>}
        {Object.entries(groups).map(([month, list]) => (
          <div key={month}>
            <div style={styles.monthHeader}>
              <span style={styles.monthLabel}>{month}</span>
              <span style={styles.monthTotal}>₹{list.reduce((s,i)=>s+(Number(i.amount)||0),0).toLocaleString('en-IN')}</span>
            </div>
            {list.map(item => (
              <div key={item.id} style={styles.card}>
                <div style={styles.leftCol}>
                  <div style={styles.rupeeCircle}>₹</div>
                  <div>
                    <p style={styles.toName}>{item.paymentTo}</p>
                    {item.note && <p style={styles.note}>{item.note}</p>}
                    <p style={styles.meta}>{item.date} · {item.createdBy}</p>
                  </div>
                </div>
                <div style={styles.rightCol}>
                  <p style={styles.amount}>₹{Number(item.amount).toLocaleString('en-IN')}</p>
                  <div style={styles.actions}>
                    <button style={styles.iconBtn} onClick={() => open(item)}><Edit2 size={14} color="#666" /></button>
                    <button style={styles.iconBtn} onClick={() => handleDelete(item)}><Trash2 size={14} color="#e74c3c" /></button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ))}
      </div>

      {modal && (
        <div style={styles.overlay}>
          <div style={styles.modal}>
            <div style={styles.modalHeader}>
              <span style={styles.modalTitle}>{editId ? t.addPayment : t.addPayment}</span>
              <button style={styles.closeBtn} onClick={() => setModal(false)}><X size={20}/></button>
            </div>
            <div style={styles.modalBody}>
              <Field label={t.paymentTo} value={form.paymentTo} onChange={v => setForm({...form, paymentTo: v})} placeholder={t.engineer} />
              <Field label={t.paymentAmount} value={form.amount} onChange={v => setForm({...form, amount: v})} type="number" />
              <Field label={t.paymentDate} value={form.date} onChange={v => setForm({...form, date: v})} type="date" />
              <div style={{ marginBottom: 14 }}>
                <label style={styles.label}>{t.photoNote}</label>
                <textarea style={styles.textarea} value={form.note} onChange={e => setForm({...form, note: e.target.value})} placeholder={t.addNote} rows={2} />
              </div>
              <button style={styles.saveBtn} onClick={handleSave} disabled={loading}>
                {loading ? t.loading : t.save}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function Field({ label, value, onChange, type='text', placeholder='' }) {
  return (
    <div style={{ marginBottom: 12 }}>
      <label style={{ fontSize: 12, color: '#666', fontWeight: 500, display: 'block', marginBottom: 4 }}>{label}</label>
      <input style={{ width: '100%', padding: '9px 12px', border: '1.5px solid #ddd', borderRadius: 8, fontSize: 14, boxSizing: 'border-box', outline: 'none' }}
        type={type} value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder} />
    </div>
  );
}

const styles = {
  page: { paddingBottom: 90 },
  topBar: { background: '#1a3a5c', padding: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  title: { color: '#fff', fontSize: 18, fontWeight: 700, margin: 0 },
  addBtn: { width: 38, height: 38, borderRadius: '50%', background: '#27ae60', border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' },
  catScroll: { display: 'flex', gap: 8, overflowX: 'auto', padding: '10px 12px 6px', scrollbarWidth: 'none' },
  chip: { flexShrink: 0, padding: '5px 12px', borderRadius: 20, border: '1px solid #ddd', background: '#fff', fontSize: 12, cursor: 'pointer', color: '#666' },
  chipActive: { background: '#1a5276', color: '#fff', border: '1px solid #1a5276' },
  totalBanner: { margin: '0 12px 10px', background: '#784212', borderRadius: 10, padding: '10px 14px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  tLabel: { fontSize: 12, color: 'rgba(255,255,255,0.75)' },
  tValue: { fontSize: 18, fontWeight: 700, color: '#fff' },
  list: { padding: '0 12px' },
  monthHeader: { display: 'flex', justifyContent: 'space-between', padding: '8px 4px 4px', borderBottom: '1px solid #eee', marginBottom: 8 },
  monthLabel: { fontSize: 13, fontWeight: 700, color: '#1a3a5c' },
  monthTotal: { fontSize: 13, fontWeight: 700, color: '#784212' },
  card: { background: '#fff', borderRadius: 12, padding: '12px', marginBottom: 8, display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', boxShadow: '0 1px 5px rgba(0,0,0,0.05)' },
  leftCol: { display: 'flex', gap: 10, flex: 1 },
  rightCol: { display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 6 },
  rupeeCircle: { width: 38, height: 38, borderRadius: '50%', background: '#fef9e7', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 16, fontWeight: 700, color: '#784212', flexShrink: 0 },
  toName: { fontSize: 14, fontWeight: 600, color: '#1a3a5c', margin: '0 0 2px' },
  note: { fontSize: 12, color: '#888', margin: '0 0 2px' },
  meta: { fontSize: 11, color: '#aaa', margin: 0 },
  amount: { fontSize: 16, fontWeight: 700, color: '#784212' },
  actions: { display: 'flex', gap: 4 },
  iconBtn: { width: 28, height: 28, background: '#f5f5f5', border: 'none', borderRadius: 6, display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' },
  overlay: { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 200, display: 'flex', alignItems: 'flex-end' },
  modal: { width: '100%', background: '#fff', borderTopLeftRadius: 20, borderTopRightRadius: 20, maxHeight: '85vh', overflow: 'hidden', display: 'flex', flexDirection: 'column' },
  modalHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '16px 20px', borderBottom: '1px solid #eee' },
  modalTitle: { fontSize: 16, fontWeight: 700, color: '#1a3a5c' },
  closeBtn: { background: 'none', border: 'none', cursor: 'pointer' },
  modalBody: { overflowY: 'auto', padding: '16px 20px 32px' },
  label: { fontSize: 12, color: '#666', fontWeight: 500 },
  textarea: { width: '100%', padding: '9px 12px', border: '1.5px solid #ddd', borderRadius: 8, fontSize: 14, resize: 'none', boxSizing: 'border-box', outline: 'none' },
  saveBtn: { width: '100%', padding: 13, background: '#1a5276', color: '#fff', border: 'none', borderRadius: 10, fontSize: 15, fontWeight: 600, cursor: 'pointer' },
  empty: { textAlign: 'center', color: '#ccc', padding: '30px 0', fontSize: 14 }
};
