import React from 'react';
import { Home, Package, CreditCard, Camera, Users } from 'lucide-react';
import { useLang } from '../context/LangContext';

export default function BottomNav({ active, setActive }) {
  const { t } = useLang();

  const tabs = [
    { id: 'dashboard', icon: Home, label: t.dashboard },
    { id: 'materials', icon: Package, label: t.materials },
    { id: 'payments', icon: CreditCard, label: t.payments },
    { id: 'photos', icon: Camera, label: t.photos },
    { id: 'users', icon: Users, label: t.users }
  ];

  return (
    <nav style={styles.nav}>
      {tabs.map(tab => {
        const Icon = tab.icon;
        const isActive = active === tab.id;
        return (
          <button key={tab.id} style={styles.tab} onClick={() => setActive(tab.id)}>
            <Icon size={22} color={isActive ? '#1a5276' : '#999'} />
            <span style={{ ...styles.label, color: isActive ? '#1a5276' : '#999', fontWeight: isActive ? 600 : 400 }}>
              {tab.label}
            </span>
            {isActive && <div style={styles.dot} />}
          </button>
        );
      })}
    </nav>
  );
}

const styles = {
  nav: {
    position: 'fixed', bottom: 0, left: 0, right: 0,
    background: '#fff', borderTop: '1px solid #eee',
    display: 'flex', zIndex: 100,
    paddingBottom: 'env(safe-area-inset-bottom)'
  },
  tab: {
    flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center',
    padding: '8px 4px', background: 'none', border: 'none', cursor: 'pointer',
    position: 'relative'
  },
  label: { fontSize: 10, marginTop: 3 },
  dot: {
    position: 'absolute', bottom: 4, width: 4, height: 4,
    borderRadius: '50%', background: '#1a5276'
  }
};
