import React, { useState, useEffect } from 'react';
import { ClipboardList, X } from 'lucide-react';
import { listenTo } from '../utils/firestore';
import { useLang } from '../context/LangContext';

export default function LogButton() {
  const { t } = useLang();
  const [open, setOpen] = useState(false);
  const [logs, setLogs] = useState([]);

  useEffect(() => {
    const unsub = listenTo('logs', setLogs, 'timestamp');
    return unsub;
  }, []);

  const fmtTime = (ts) => {
    if (!ts) return '';
    const d = ts.toDate ? ts.toDate() : new Date(ts);
    return d.toLocaleString('en-IN', { day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit' });
  };

  const actionColor = (action) => {
    if (action.includes('ADD')) return '#27ae60';
    if (action.includes('EDIT')) return '#e67e22';
    if (action.includes('DELETE')) return '#e74c3c';
    return '#3498db';
  };

  const actionIcon = (action) => {
    if (action.includes('MATERIAL')) return '📦';
    if (action.includes('PAYMENT')) return '💰';
    if (action.includes('PHOTO')) return '📷';
    return '📝';
  };

  return (
    <>
      <button style={styles.fab} onClick={() => setOpen(true)} title={t.activityLog}>
        <ClipboardList size={22} color="#fff" />
        {logs.length > 0 && <span style={styles.badge}>{logs.length > 99 ? '99+' : logs.length}</span>}
      </button>

      {open && (
        <div style={styles.overlay} onClick={() => setOpen(false)}>
          <div style={styles.drawer} onClick={e => e.stopPropagation()}>
            <div style={styles.drawerHeader}>
              <span style={styles.drawerTitle}>{t.activityLog}</span>
              <button style={styles.closeBtn} onClick={() => setOpen(false)}><X size={20}/></button>
            </div>
            <div style={styles.logList}>
              {logs.length === 0 && <p style={styles.empty}>{t.noData}</p>}
              {logs.map(log => (
                <div key={log.id} style={styles.logItem}>
                  <div style={styles.logLeft}>
                    <span style={styles.logIcon}>{actionIcon(log.action)}</span>
                    <div>
                      <p style={styles.logDetails}>{log.details}</p>
                      <p style={styles.logMeta}>
                        <span style={{ ...styles.logBadge, background: actionColor(log.action) + '22', color: actionColor(log.action) }}>
                          {log.action.replace(/_/g, ' ')}
                        </span>
                        &nbsp;·&nbsp;{log.userName}
                      </p>
                    </div>
                  </div>
                  <span style={styles.logTime}>{fmtTime(log.timestamp)}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </>
  );
}

const styles = {
  fab: {
    position: 'fixed', bottom: 76, right: 16,
    width: 52, height: 52, borderRadius: '50%',
    background: '#1a5276', border: 'none',
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    cursor: 'pointer', boxShadow: '0 4px 14px rgba(26,82,118,0.4)',
    zIndex: 99
  },
  badge: {
    position: 'absolute', top: -4, right: -4,
    background: '#e74c3c', color: '#fff',
    fontSize: 10, borderRadius: 10, padding: '2px 5px', fontWeight: 700
  },
  overlay: {
    position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)',
    zIndex: 200, display: 'flex', alignItems: 'flex-end'
  },
  drawer: {
    width: '100%', background: '#fff',
    borderTopLeftRadius: 20, borderTopRightRadius: 20,
    maxHeight: '75vh', display: 'flex', flexDirection: 'column'
  },
  drawerHeader: {
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    padding: '16px 20px', borderBottom: '1px solid #eee'
  },
  drawerTitle: { fontSize: 16, fontWeight: 700, color: '#1a3a5c' },
  closeBtn: { background: 'none', border: 'none', cursor: 'pointer', padding: 4 },
  logList: { overflowY: 'auto', flex: 1, padding: '8px 0' },
  logItem: {
    display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between',
    padding: '12px 20px', borderBottom: '1px solid #f5f5f5'
  },
  logLeft: { display: 'flex', gap: 10, flex: 1 },
  logIcon: { fontSize: 18, marginTop: 1 },
  logDetails: { fontSize: 13, color: '#333', margin: '0 0 4px' },
  logMeta: { fontSize: 11, color: '#888', margin: 0 },
  logBadge: { fontSize: 10, padding: '2px 6px', borderRadius: 4, fontWeight: 600 },
  logTime: { fontSize: 11, color: '#aaa', whiteSpace: 'nowrap', marginLeft: 8 },
  empty: { textAlign: 'center', color: '#aaa', padding: 32, fontSize: 14 }
};
