import React, { useEffect, useState } from 'react';
import { Plus, Edit2, Trash2, X, Search } from 'lucide-react';
import { listenTo, addMaterial, updateMaterial, deleteMaterial, uploadImage } from '../utils/firestore';
import { useLang } from '../context/LangContext';
import { useAuth } from '../context/AuthContext';

const emptyForm = { name: '', category: 'cement', quantity: '', unit: '', perUnit: '', totalCost: '', date: new Date().toISOString().split('T')[0], imageUrl: '' };

export default function Materials() {
  const { t } = useLang();
  const { userProfile } = useAuth();
  const [items, setItems] = useState([]);
  const [modal, setModal] = useState(false);
  const [form, setForm] = useState(emptyForm);
  const [editId, setEditId] = useState(null);
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState('');
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(false);
  const [filterCat, setFilterCat] = useState('all');

  useEffect(() => { return listenTo('materials', setItems); }, []);

  const open = (item = null) => {
    if (item) { setForm({ ...item }); setEditId(item.id); setImagePreview(item.imageUrl || ''); }
    else { setForm(emptyForm); setEditId(null); setImagePreview(''); }
    setImageFile(null);
    setModal(true);
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setImageFile(file);
    setImagePreview(URL.createObjectURL(file));
  };

  const calcTotal = (qty, per) => {
    const q = parseFloat(qty) || 0, p = parseFloat(per) || 0;
    return q * p;
  };

  const handleFieldChange = (k, v) => {
    const updated = { ...form, [k]: v };
    if (k === 'quantity' || k === 'perUnit') {
      updated.totalCost = calcTotal(updated.quantity, updated.perUnit);
    }
    setForm(updated);
  };

  const handleSave = async () => {
    if (!form.name || !form.quantity) return;
    setLoading(true);
    let imageUrl = form.imageUrl || '';
    if (imageFile) imageUrl = await uploadImage(imageFile, 'materials');
    const data = { ...form, imageUrl, totalCost: Number(form.totalCost) };
    if (editId) await updateMaterial(editId, data, userProfile);
    else await addMaterial(data, userProfile);
    setModal(false);
    setLoading(false);
  };

  const handleDelete = async (item) => {
    if (!window.confirm(t.confirmDelete)) return;
    await deleteMaterial(item.id, item.name, userProfile);
  };

  const filtered = items.filter(i => {
    const matchSearch = i.name?.toLowerCase().includes(search.toLowerCase());
    const matchCat = filterCat === 'all' || i.category === filterCat;
    return matchSearch && matchCat;
  });

  const total = filtered.reduce((s, i) => s + (Number(i.totalCost) || 0), 0);

  const catKeys = Object.keys(t.categories);

  return (
    <div style={styles.page}>
      <div style={styles.topBar}>
        <h2 style={styles.title}>{t.materials}</h2>
        <button style={styles.addBtn} onClick={() => open()}>
          <Plus size={18} color="#fff" />
        </button>
      </div>

      {/* Search */}
      <div style={styles.searchRow}>
        <div style={styles.searchBox}>
          <Search size={15} color="#aaa" />
          <input style={styles.searchInput} placeholder={t.filter + '...'} value={search} onChange={e => setSearch(e.target.value)} />
        </div>
      </div>

      {/* Category filters */}
      <div style={styles.catScroll}>
        <button style={{ ...styles.catChip, ...(filterCat === 'all' ? styles.catActive : {}) }} onClick={() => setFilterCat('all')}>{t.all}</button>
        {catKeys.map(k => (
          <button key={k} style={{ ...styles.catChip, ...(filterCat === k ? styles.catActive : {}) }} onClick={() => setFilterCat(k)}>
            {t.categories[k]}
          </button>
        ))}
      </div>

      {/* Total */}
      <div style={styles.totalBanner}>
        <span style={styles.totalLabel}>{t.totalCost}</span>
        <span style={styles.totalValue}>₹{Number(total).toLocaleString('en-IN')}</span>
      </div>

      {/* List */}
      <div style={styles.list}>
        {filtered.length === 0 && <p style={styles.empty}>{t.noData}</p>}
        {filtered.map(item => (
          <div key={item.id} style={styles.card}>
            <div style={styles.cardLeft}>
              {item.imageUrl
                ? <img src={item.imageUrl} alt={item.name} style={styles.thumb} />
                : <div style={styles.thumbPlaceholder}><span style={{ fontSize: 22 }}>{catEmoji(item.category)}</span></div>
              }
              <div style={{ flex: 1 }}>
                <p style={styles.itemName}>{item.name}</p>
                <p style={styles.itemMeta}>{item.quantity} {item.unit} · {t.categories[item.category] || item.category}</p>
                <p style={styles.itemMeta}>{item.date} · {item.createdBy}</p>
              </div>
            </div>
            <div style={styles.cardRight}>
              <p style={styles.itemCost}>₹{Number(item.totalCost).toLocaleString('en-IN')}</p>
              <div style={styles.actions}>
                <button style={styles.iconBtn} onClick={() => open(item)}><Edit2 size={15} color="#666" /></button>
                <button style={styles.iconBtn} onClick={() => handleDelete(item)}><Trash2 size={15} color="#e74c3c" /></button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Modal */}
      {modal && (
        <div style={styles.overlay}>
          <div style={styles.modal}>
            <div style={styles.modalHeader}>
              <span style={styles.modalTitle}>{editId ? t.editMaterial : t.addMaterial}</span>
              <button style={styles.closeBtn} onClick={() => setModal(false)}><X size={20} /></button>
            </div>
            <div style={styles.modalBody}>
              {/* Image upload */}
              <div style={styles.imgUploadArea} onClick={() => document.getElementById('mat-img').click()}>
                {imagePreview
                  ? <img src={imagePreview} alt="preview" style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: 10 }} />
                  : <div style={{ textAlign: 'center', color: '#aaa' }}>
                      <span style={{ fontSize: 28 }}>📷</span>
                      <p style={{ fontSize: 12, margin: '4px 0 0' }}>{t.imageOptional}</p>
                    </div>
                }
                <input id="mat-img" type="file" accept="image/*" style={{ display: 'none' }} onChange={handleImageChange} />
              </div>

              <Field label={t.materialName} value={form.name} onChange={v => handleFieldChange('name', v)} />

              <div style={styles.row2}>
                <div style={{ flex: 1 }}>
                  <label style={styles.label}>{t.category}</label>
                  <select style={styles.select} value={form.category} onChange={e => handleFieldChange('category', e.target.value)}>
                    {catKeys.map(k => <option key={k} value={k}>{t.categories[k]}</option>)}
                  </select>
                </div>
                <div style={{ flex: 1 }}>
                  <label style={styles.label}>{t.unit}</label>
                  <select style={styles.select} value={form.unit} onChange={e => handleFieldChange('unit', e.target.value)}>
                    {t.units.map(u => <option key={u} value={u}>{u}</option>)}
                  </select>
                </div>
              </div>

              <div style={styles.row2}>
                <div style={{ flex: 1 }}>
                  <label style={styles.label}>{t.quantity}</label>
                  <input style={styles.input} type="number" value={form.quantity} onChange={e => handleFieldChange('quantity', e.target.value)} />
                </div>
                <div style={{ flex: 1 }}>
                  <label style={styles.label}>{t.perUnit}</label>
                  <input style={styles.input} type="number" value={form.perUnit} onChange={e => handleFieldChange('perUnit', e.target.value)} />
                </div>
              </div>

              <div style={styles.totalBox}>
                <span style={styles.totalLabel2}>{t.totalCost}</span>
                <span style={styles.totalVal}>₹{Number(form.totalCost || 0).toLocaleString('en-IN')}</span>
              </div>

              <Field label={t.date} value={form.date} onChange={v => handleFieldChange('date', v)} type="date" />

              <button style={styles.saveBtn} onClick={handleSave} disabled={loading}>
                {loading ? t.loading : t.save}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function Field({ label, value, onChange, type = 'text' }) {
  return (
    <div style={{ marginBottom: 12 }}>
      <label style={{ fontSize: 12, color: '#666', fontWeight: 500, display: 'block', marginBottom: 4 }}>{label}</label>
      <input style={{ width: '100%', padding: '9px 12px', border: '1.5px solid #ddd', borderRadius: 8, fontSize: 14, boxSizing: 'border-box', outline: 'none' }}
        type={type} value={value} onChange={e => onChange(e.target.value)} />
    </div>
  );
}

function catEmoji(cat) {
  const map = { cement: '🧱', sand: '⛱', brick: '🧱', steel: '⚙️', paint: '🎨', wood: '🪵', electrical: '⚡', plumbing: '🔧', other: '📦' };
  return map[cat] || '📦';
}

