  totalLabel: { fontSize: 12, color: 'rgba(255,255,255,0.7)' },
  totalValue: { fontSize: 18, fontWeight: 700, color: '#fff' },
  list: { padding: '0 12px' },
  card: { background: '#fff', borderRadius: 12, padding: 12, marginBottom: 10, display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', boxShadow: '0 1px 6px rgba(0,0,0,0.06)' },
  cardLeft: { display: 'flex', gap: 10, flex: 1 },
  cardRight: { display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: 6 },
  thumb: { width: 52, height: 52, borderRadius: 8, objectFit: 'cover', flexShrink: 0 },
  thumbPlaceholder: { width: 52, height: 52, borderRadius: 8, background: '#f0f4f8', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 },
