import React, { useEffect, useState } from 'react';
import { Plus, X, Camera } from 'lucide-react';
import { listenTo, addPhoto, uploadImage } from '../utils/firestore';
import { useLang } from '../context/LangContext';
import { useAuth } from '../context/AuthContext';

export default function Photos() {
  const { t } = useLang();
  const { userProfile } = useAuth();
  const [photos, setPhotos] = useState([]);
  const [modal, setModal] = useState(false);
  const [imageFile, setImageFile] = useState(null);
  const [imagePreview, setImagePreview] = useState('');
  const [note, setNote] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [loading, setLoading] = useState(false);
  const [lightbox, setLightbox] = useState(null);

  useEffect(() => { return listenTo('photos', setPhotos); }, []);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setImageFile(file);
    setImagePreview(URL.createObjectURL(file));
  };

  const handleUpload = async () => {
    if (!imageFile) return;
    setLoading(true);
    const imageUrl = await uploadImage(imageFile, 'daily-photos');
    await addPhoto({ imageUrl, note, date }, userProfile);
    setModal(false);
    setImageFile(null);
    setImagePreview('');
    setNote('');
    setLoading(false);
  };

  // Group by date
  const groups = {};
  photos.forEach(p => {
    const key = p.date || 'Unknown';
    if (!groups[key]) groups[key] = [];
    groups[key].push(p);
  });

  return (
    <div style={styles.page}>
      <div style={styles.topBar}>
        <h2 style={styles.title}>{t.photos}</h2>
        <button style={styles.addBtn} onClick={() => setModal(true)}>
          <Plus size={18} color="#fff" />
        </button>
      </div>

      <div style={styles.list}>
        {Object.keys(groups).length === 0 && (
          <div style={styles.emptyState}>
            <Camera size={48} color="#ccc" />
            <p style={styles.emptyText}>{t.noData}</p>
            <p style={{ fontSize: 12, color: '#ccc' }}>{t.uploadPhoto}</p>
          </div>
        )}
        {Object.entries(groups).sort((a,b) => b[0].localeCompare(a[0])).map(([date, list]) => (
          <div key={date}>
            <div style={styles.dateHeader}>{formatDate(date)}</div>
            <div style={styles.photoGrid}>
              {list.map(photo => (
                <div key={photo.id} style={styles.photoCard} onClick={() => setLightbox(photo)}>
                  <img src={photo.imageUrl} alt={photo.note || date} style={styles.photoImg} />
                  {photo.note && <div style={styles.photoOverlay}><p style={styles.photoNote}>{photo.note}</p></div>}
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>

      {/* Upload modal */}
      {modal && (
        <div style={styles.overlay}>
          <div style={styles.modal}>
            <div style={styles.modalHeader}>
              <span style={styles.modalTitle}>{t.uploadPhoto}</span>
              <button style={styles.closeBtn} onClick={() => setModal(false)}><X size={20}/></button>
            </div>
            <div style={styles.modalBody}>
              <div style={styles.uploadArea} onClick={() => document.getElementById('photo-input').click()}>
                {imagePreview
                  ? <img src={imagePreview} alt="preview" style={{ width: '100%', height: '100%', objectFit: 'contain' }} />
                  : <>
                      <Camera size={40} color="#ccc" />
                      <p style={{ color: '#aaa', fontSize: 13, marginTop: 8 }}>{t.uploadPhoto}</p>
                    </>
                }
                <input id="photo-input" type="file" accept="image/*" capture="environment" style={{ display: 'none' }} onChange={handleImageChange} />
              </div>
              <div style={{ marginBottom: 12 }}>
                <label style={styles.label}>{t.date}</label>
                <input style={styles.input} type="date" value={date} onChange={e => setDate(e.target.value)} />
              </div>
              <div style={{ marginBottom: 16 }}>
                <label style={styles.label}>{t.addNote}</label>
                <textarea style={styles.textarea} value={note} onChange={e => setNote(e.target.value)} placeholder={t.addNote} rows={2} />
              </div>
              <button style={{ ...styles.saveBtn, opacity: imageFile ? 1 : 0.5 }} onClick={handleUpload} disabled={!imageFile || loading}>
                {loading ? t.loading : t.uploadPhoto}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Lightbox */}
      {lightbox && (
        <div style={styles.lightbox} onClick={() => setLightbox(null)}>
          <button style={styles.lightboxClose}><X size={24} color="#fff"/></button>
          <img src={lightbox.imageUrl} alt={lightbox.note} style={styles.lightboxImg} />
          {lightbox.note && <p style={styles.lightboxNote}>{lightbox.note}</p>}
          <p style={styles.lightboxMeta}>{lightbox.date} · {lightbox.createdBy}</p>
        </div>
      )}
    </div>
  );
}

function formatDate(d) {
  const date = new Date(d);
  if (isNaN(date)) return d;
  return date.toLocaleDateString('en-IN', { weekday: 'short', year: 'numeric', month: 'long', day: 'numeric' });
}

const styles = {
  page: { paddingBottom: 90 },
  topBar: { background: '#1a3a5c', padding: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  title: { color: '#fff', fontSize: 18, fontWeight: 700, margin: 0 },
  addBtn: { width: 38, height: 38, borderRadius: '50%', background: '#27ae60', border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' },
  list: { padding: '12px 12px 0' },
  dateHeader: { fontSize: 12, fontWeight: 700, color: '#1a3a5c', background: '#eaf1f8', borderRadius: 8, padding: '5px 10px', marginBottom: 8 },
  photoGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 6, marginBottom: 14 },
  photoCard: { aspectRatio: '1', borderRadius: 10, overflow: 'hidden', position: 'relative', cursor: 'pointer', background: '#f0f0f0' },
  photoImg: { width: '100%', height: '100%', objectFit: 'cover' },
  photoOverlay: { position: 'absolute', bottom: 0, left: 0, right: 0, background: 'rgba(0,0,0,0.5)', padding: '4px 6px' },
  photoNote: { color: '#fff', fontSize: 9, margin: 0, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' },
  emptyState: { display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '60px 0', gap: 8 },
  emptyText: { color: '#bbb', fontSize: 14, margin: 0 },
  overlay: { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', zIndex: 200, display: 'flex', alignItems: 'flex-end' },
  modal: { width: '100%', background: '#fff', borderTopLeftRadius: 20, borderTopRightRadius: 20, maxHeight: '85vh', overflow: 'hidden', display: 'flex', flexDirection: 'column' },
  modalHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '16px 20px', borderBottom: '1px solid #eee' },
  modalTitle: { fontSize: 16, fontWeight: 700, color: '#1a3a5c' },
  closeBtn: { background: 'none', border: 'none', cursor: 'pointer' },
  modalBody: { overflowY: 'auto', padding: '16px 20px 32px' },
  uploadArea: { width: '100%', height: 200, background: '#f8f9fa', border: '2px dashed #ddd', borderRadius: 12, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', marginBottom: 16, overflow: 'hidden' },
  label: { fontSize: 12, color: '#666', fontWeight: 500, display: 'block', marginBottom: 4 },
  input: { width: '100%', padding: '9px 12px', border: '1.5px solid #ddd', borderRadius: 8, fontSize: 14, boxSizing: 'border-box', outline: 'none' },
  textarea: { width: '100%', padding: '9px 12px', border: '1.5px solid #ddd', borderRadius: 8, fontSize: 14, resize: 'none', boxSizing: 'border-box', outline: 'none' },
  saveBtn: { width: '100%', padding: 13, background: '#1a5276', color: '#fff', border: 'none', borderRadius: 10, fontSize: 15, fontWeight: 600, cursor: 'pointer' },
  lightbox: { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.92)', zIndex: 300, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: 16 },
  lightboxClose: { position: 'absolute', top: 20, right: 20, background: 'rgba(255,255,255,0.2)', border: 'none', borderRadius: '50%', width: 40, height: 40, display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' },
  lightboxImg: { maxWidth: '100%', maxHeight: '75vh', borderRadius: 12, objectFit: 'contain' },
  lightboxNote: { color: '#fff', fontSize: 14, marginTop: 12, textAlign: 'center' },
  lightboxMeta: { color: 'rgba(255,255,255,0.5)', fontSize: 12 }
};
